class APIClient {
    let baseURL = "https://api.yourtradingplatform.com"

    func executeTrade(_ trade: Trade, completion: @escaping (Bool) -> Void) {
        guard let url = URL(string: "\(baseURL)/executeTrade") else { return }
        var request = URLRequest(url: url)
        request.httpMethod = "POST"
        request.setValue("application/json", forHTTPHeaderField: "Content-Type")
        request.httpBody = try? JSONEncoder().encode(trade)

        let task = URLSession.shared.dataTask(with: request) { data, response, error in
            guard error == nil, let data = data else {
                completion(false)
                return
            }
            let success = (response as? HTTPURLResponse)?.statusCode == 200
            completion(success)
        }
        task.resume()
    }
}

